# Commit report to GitHub
cd /root/.openclaw/workspace
# GITHUB_TOKEN should be set as environment variable
git add "$REPORT_FILE"
git commit -m "Daily queue status report: ${REPORT_DATE} (Patricia update)"
git push origin master

# Send email to Captain
python3 << PYTHON_EOF
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from email.mime.application import MIMEApplication
import os

# Email configuration
smtp_server = "smtp.hostinger.com"
smtp_port = 587
sender_email = "miles@myl0nr0s.cloud"
sender_password = "Myl0n.R0s"
recipient_email = "antonio.hudnall@gmail.com"

# Read report
with open("$REPORT_FILE", "r") as f:
    report_content = f.read()

# Create message
msg = MIMEMultipart()
msg["From"] = sender_email
msg["To"] = recipient_email
msg["Subject"] = "$EMAIL_SUBJECT"

# Attach report content
msg.attach(MIMEText(report_content, "plain"))

# Attach report file
with open("$REPORT_FILE", "rb") as f:
    attach = MIMEApplication(f.read(), _subtype="md")
    attach.add_header("Content-Disposition", "attachment", filename=os.path.basename("$REPORT_FILE"))
    msg.attach(attach)

# Send email
try:
    server = smtplib.SMTP(smtp_server, smtp_port)
    server.starttls()
    server.login(sender_email, sender_password)
    server.send_message(msg)
    server.quit()
    print("✓ Email sent successfully to $recipient_email")
except Exception as e:
    print(f"✗ Email failed: {e}")
PYTHON_EOF

echo "Daily queue report with email complete: $REPORT_FILE"